package com.maum.backend.service

import com.maum.backend.entity.follow.FollowEntity
import com.maum.backend.entity.user.UserEntity
import com.maum.backend.exception.AlreadyFollowingException
import com.maum.backend.exception.NotFoundException
import com.maum.backend.exception.SelfFollowException
import com.maum.backend.repository.follow.FollowRepository
import com.maum.backend.repository.user.UserRepository
import org.assertj.core.api.Assertions.assertThat
import org.junit.jupiter.api.Test
import org.junit.jupiter.api.assertThrows
import org.junit.jupiter.api.extension.ExtendWith
import org.mockito.InjectMocks
import org.mockito.Mock
import org.mockito.Mockito.never
import org.mockito.Mockito.verify
import org.mockito.Mockito.`when`
import org.mockito.junit.jupiter.MockitoExtension
import org.mockito.kotlin.any
import org.mockito.kotlin.argumentCaptor
import java.time.LocalDateTime
import java.util.Optional

@ExtendWith(MockitoExtension::class)
class UserServiceTest {

    @Mock
    private lateinit var userRepository: UserRepository

    @Mock
    private lateinit var followRepository: FollowRepository

    @InjectMocks
    private lateinit var userService: UserService

    // =============================================
    // follow() 성공 케이스
    // =============================================

    @Test
    fun `should follow user successfully when valid follower and followee are given`() {
        // given
        val followerId = "follower-user-id"
        val followeeId = "followee-user-id"
        val followerEntity = createUserEntity(followerId)
        val followeeEntity = createUserEntity(followeeId)
        val savedFollow = createFollowEntity(followerId, followeeId)

        `when`(userRepository.findById(followerId)).thenReturn(Optional.of(followerEntity))
        `when`(userRepository.findById(followeeId)).thenReturn(Optional.of(followeeEntity))
        `when`(followRepository.existsByFollowerIdAndFolloweeId(followerId, followeeId)).thenReturn(false)
        `when`(followRepository.save(any())).thenReturn(savedFollow)

        // when
        val result = userService.follow(followerId, followeeId)

        // then
        assertThat(result).isNotNull
        assertThat(result.followerId).isEqualTo(followerId)
        assertThat(result.followeeId).isEqualTo(followeeId)
        verify(followRepository).save(any())
    }

    @Test
    fun `should save follow entity with correct follower and followee ids`() {
        // given
        val followerId = "follower-id"
        val followeeId = "followee-id"
        val followerEntity = createUserEntity(followerId)
        val followeeEntity = createUserEntity(followeeId)
        val savedFollow = createFollowEntity(followerId, followeeId)

        `when`(userRepository.findById(followerId)).thenReturn(Optional.of(followerEntity))
        `when`(userRepository.findById(followeeId)).thenReturn(Optional.of(followeeEntity))
        `when`(followRepository.existsByFollowerIdAndFolloweeId(followerId, followeeId)).thenReturn(false)
        `when`(followRepository.save(any())).thenReturn(savedFollow)

        val captor = argumentCaptor<FollowEntity>()

        // when
        userService.follow(followerId, followeeId)

        // then
        verify(followRepository).save(captor.capture())
        assertThat(captor.firstValue.followerId).isEqualTo(followerId)
        assertThat(captor.firstValue.followeeId).isEqualTo(followeeId)
    }

    @Test
    fun `should return follow count after following`() {
        // given
        val followerId = "follower-id"
        val followeeId = "followee-id"
        val followerEntity = createUserEntity(followerId)
        val followeeEntity = createUserEntity(followeeId)
        val savedFollow = createFollowEntity(followerId, followeeId)
        val expectedFollowingCount = 5L

        `when`(userRepository.findById(followerId)).thenReturn(Optional.of(followerEntity))
        `when`(userRepository.findById(followeeId)).thenReturn(Optional.of(followeeEntity))
        `when`(followRepository.existsByFollowerIdAndFolloweeId(followerId, followeeId)).thenReturn(false)
        `when`(followRepository.save(any())).thenReturn(savedFollow)
        `when`(followRepository.countByFollowerId(followerId)).thenReturn(expectedFollowingCount)

        // when
        userService.follow(followerId, followeeId)

        // then
        val followingCount = followRepository.countByFollowerId(followerId)
        assertThat(followingCount).isEqualTo(expectedFollowingCount)
    }

    // =============================================
    // follow() 실패 케이스 - 자기 자신 팔로우
    // =============================================

    @Test
    fun `should throw SelfFollowException when follower tries to follow themselves`() {
        // given
        val userId = "same-user-id"

        // when & then
        assertThrows<SelfFollowException> {
            userService.follow(userId, userId)
        }
    }

    @Test
    fun `should not call repository when follower and followee are same`() {
        // given
        val userId = "same-user-id"

        // when & then
        assertThrows<SelfFollowException> {
            userService.follow(userId, userId)
        }
        verify(userRepository, never()).findById(any())
        verify(followRepository, never()).existsByFollowerIdAndFolloweeId(any(), any())
        verify(followRepository, never()).save(any())
    }

    // =============================================
    // follow() 실패 케이스 - 이미 팔로우 중
    // =============================================

    @Test
    fun `should throw AlreadyFollowingException when already following the user`() {
        // given
        val followerId = "follower-id"
        val followeeId = "followee-id"
        val followerEntity = createUserEntity(followerId)
        val followeeEntity = createUserEntity(followeeId)

        `when`(userRepository.findById(followerId)).thenReturn(Optional.of(followerEntity))
        `when`(userRepository.findById(followeeId)).thenReturn(Optional.of(followeeEntity))
        `when`(followRepository.existsByFollowerIdAndFolloweeId(followerId, followeeId)).thenReturn(true)

        // when & then
        assertThrows<AlreadyFollowingException> {
            userService.follow(followerId, followeeId)
        }
    }

    @Test
    fun `should not save follow entity when already following`() {
        // given
        val followerId = "follower-id"
        val followeeId = "followee-id"
        val followerEntity = createUserEntity(followerId)
        val followeeEntity = createUserEntity(followeeId)

        `when`(userRepository.findById(followerId)).thenReturn(Optional.of(followerEntity))
        `when`(userRepository.findById(followeeId)).thenReturn(Optional.of(followeeEntity))
        `when`(followRepository.existsByFollowerIdAndFolloweeId(followerId, followeeId)).thenReturn(true)

        // when & then
        assertThrows<AlreadyFollowingException> {
            userService.follow(followerId, followeeId)
        }
        verify(followRepository, never()).save(any())
    }

    // =============================================
    // follow() 실패 케이스 - 사용자 미존재
    // =============================================

    @Test
    fun `should throw NotFoundException when follower user does not exist`() {
        // given
        val followerId = "non-existent-follower"
        val followeeId = "followee-id"

        `when`(userRepository.findById(followerId)).thenReturn(Optional.empty())

        // when & then
        assertThrows<NotFoundException> {
            userService.follow(followerId, followeeId)
        }
    }

    @Test
    fun `should throw NotFoundException when followee user does not exist`() {
        // given
        val followerId = "follower-id"
        val followeeId = "non-existent-followee"
        val followerEntity = createUserEntity(followerId)

        `when`(userRepository.findById(followerId)).thenReturn(Optional.of(followerEntity))
        `when`(userRepository.findById(followeeId)).thenReturn(Optional.empty())

        // when & then
        assertThrows<NotFoundException> {
            userService.follow(followerId, followeeId)
        }
    }

    @Test
    fun `should not check follow existence when follower not found`() {
        // given
        val followerId = "non-existent-follower"
        val followeeId = "followee-id"

        `when`(userRepository.findById(followerId)).thenReturn(Optional.empty())

        // when & then
        assertThrows<NotFoundException> {
            userService.follow(followerId, followeeId)
        }
        verify(followRepository, never()).existsByFollowerIdAndFolloweeId(any(), any())
        verify(followRepository, never()).save(any())
    }

    // =============================================
    // follow() 엣지 케이스
    // =============================================

    @Test
    fun `should throw IllegalArgumentException when followerId is blank`() {
        // given
        val followerId = ""
        val followeeId = "followee-id"

        // when & then
        assertThrows<IllegalArgumentException> {
            userService.follow(followerId, followeeId)
        }
    }

    @Test
    fun `should throw IllegalArgumentException when followeeId is blank`() {
        // given
        val followerId = "follower-id"
        val followeeId = ""

        // when & then
        assertThrows<IllegalArgumentException> {
            userService.follow(followerId, followeeId)
        }
    }

    @Test
    fun `should throw IllegalArgumentException when followerId is whitespace only`() {
        // given
        val followerId = "   "
        val followeeId = "followee-id"

        // when & then
        assertThrows<IllegalArgumentException> {
            userService.follow(followerId, followeeId)
        }
    }

    // =============================================
    // unfollow() 성공 케이스
    // =============================================

    @Test
    fun `should unfollow user successfully when follow relationship exists`() {
        // given
        val followerId = "follower-id"
        val followeeId = "followee-id"
        val followEntity = createFollowEntity(followerId, followeeId)

        `when`(followRepository.findByFollowerIdAndFolloweeId(followerId, followeeId))
            .thenReturn(Optional.of(followEntity))

        // when
        userService.unfollow(followerId, followeeId)

        // then
        verify(followRepository).delete(followEntity)
    }

    // =============================================
    // unfollow() 실패 케이스
    // =============================================

    @Test
    fun `should throw NotFoundException when trying to unfollow non-existing follow relationship`() {
        // given
        val followerId = "follower-id"
        val followeeId = "followee-id"

        `when`(followRepository.findByFollowerIdAndFolloweeId(followerId, followeeId))
            .thenReturn(Optional.empty())

        // when & then
        assertThrows<NotFoundException> {
            userService.unfollow(followerId, followeeId)
        }
        verify(followRepository, never()).delete(any())
    }

    @Test
    fun `should throw SelfFollowException when trying to unfollow themselves`() {
        // given
        val userId = "same-user-id"

        // when & then
        assertThrows<SelfFollowException> {
            userService.unfollow(userId, userId)
        }
        verify(followRepository, never()).findByFollowerIdAndFolloweeId(any(), any())
    }

    // =============================================
    // getFollowers() 성공 케이스
    // =============================================

    @Test
    fun `should return followers list for given user`() {
        // given
        val userId = "user-id"
        val followers = listOf(
            createFollowEntity("follower-1", userId),
            createFollowEntity("follower-2", userId),
            createFollowEntity("follower-3", userId),
        )

        `when`(followRepository.findByFolloweeId(userId)).thenReturn(followers)

        // when
        val result = userService.getFollowers(userId)

        // then
        assertThat(result).hasSize(3)
        verify(followRepository).findByFolloweeId(userId)
    }

    @Test
    fun `should return empty list when user has no followers`() {
        // given
        val userId = "user-with-no-followers"

        `when`(followRepository.findByFolloweeId(userId)).thenReturn(emptyList())

        // when
        val result = userService.getFollowers(userId)

        // then
        assertThat(result).isEmpty()
        verify(followRepository).findByFolloweeId(userId)
    }

    // =============================================
    // getFollowings() 성공 케이스
    // =============================================

    @Test
    fun `should return followings list for given user`() {
        // given
        val userId = "user-id"
        val followings = listOf(
            createFollowEntity(userId, "followee-1"),
            createFollowEntity(userId, "followee-2"),
        )

        `when`(followRepository.findByFollowerId(userId)).thenReturn(followings)

        // when
        val result = userService.getFollowings(userId)

        // then
        assertThat(result).hasSize(2)
        verify(followRepository).findByFollowerId(userId)
    }

    @Test
    fun `should return empty list when user follows nobody`() {
        // given
        val userId = "user-following-nobody"

        `when`(followRepository.findByFollowerId(userId)).thenReturn(emptyList())

        // when
        val result = userService.getFollowings(userId)

        // then
        assertThat(result).isEmpty()
    }

    // =============================================
    // isFollowing() 케이스
    // =============================================

    @Test
    fun `should return true when follow relationship exists`() {
        // given
        val followerId = "follower-id"
        val followeeId = "followee-id"

        `when`(followRepository.existsByFollowerIdAndFolloweeId(followerId, followeeId)).thenReturn(true)

        // when
        val result = userService.isFollowing(followerId, followeeId)

        // then
        assertThat(result).isTrue()
    }

    @Test
    fun `should return false when follow relationship does not exist`() {
        // given
        val followerId = "follower-id"
        val followeeId = "followee-id"

        `when`(followRepository.existsByFollowerIdAndFolloweeId(followerId, followeeId)).thenReturn(false)

        // when
        val result = userService.isFollowing(followerId, followeeId)

        // then
        assertThat(result).isFalse()
    }

    @Test
    fun `should return false when checking if user follows themselves`() {
        // given
        val userId = "same-user-id"

        // when
        val result = userService.isFollowing(userId, userId)

        // then
        assertThat(result).isFalse()
        verify(followRepository, never()).existsByFollowerIdAndFolloweeId(any(), any())
    }

    // =============================================
    // 헬퍼 메서드
    // =============================================

    private fun createUserEntity(userId: String): UserEntity {
        return UserEntity(
            id = userId,
            nickname = "user_$userId",
            status = 0,
            createdAt = LocalDateTime.now(),
            updatedAt = LocalDateTime.now(),
        )
    }

    private fun createFollowEntity(followerId: String, followeeId: String): FollowEntity {
        return FollowEntity(
            id = "follow-${followerId}-${followeeId}",
            followerId = followerId,
            followeeId = followeeId,
            createdAt = LocalDateTime.now(),
        )
    }
}

