        }
    }

    @Test
    fun `should throw IllegalArgumentException when followerId is whitespace only`() {
        // given
        val followerId = "   "
        val followeeId = "followee-id"

        // when & then
        assertThrows<IllegalArgumentException> {
            userService.follow(followerId, followeeId)
        }
    }

    // =============================================
    // unfollow() 성공 케이스
    // =============================================

    @Test
    fun `should unfollow user successfully when follow relationship exists`() {
